module shift_register_4bit
    (
        input clk,
        input load,
        input [3:0] din,
        output reg [3:0] q
    );
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk)
    begin
        if (load)
            q <= din;
        else
            q <= {q[2:0], 1'b0};
    end

endmodule
